(()=>{"use strict";self.addEventListener("push",t=>{let i;if(t.data){try{i=t.data.json()}catch{i={title:"Notification",body:t.data.text()}}t.waitUntil(self.registration.showNotification(i.title,{body:i.body,icon:i.icon??"/icons/icon-192.png",badge:i.badge??"/icons/icon-192.png",tag:i.tag,data:{url:i.url??"/"}}))}}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.url??"/";t.waitUntil((async()=>{for(let t of(await self.clients.matchAll({type:"window",includeUncontrolled:!0})))if("focus"in t){if(await t.focus(),"navigate"in t)try{await t.navigate(i)}catch{}return}await self.clients.openWindow(i)})())})})();